import { Component } from '@angular/core';
import { RouterLink } from '@angular/router';

@Component({
  selector: 'app-checkout-page',
  standalone: true,
  imports: [RouterLink],
  template: `
    <section class="detail__panel">
      <h1>Seleccionar método de pago</h1>
      <p>Esta etapa queda reservada para la pasarela de pago que se implementará más adelante.</p>
      <a class="back-link" routerLink="/carrito">Volver al carrito</a>
    </section>
  `,
})
export class CheckoutPageComponent {}
